using namespace std;
inline int read(){
    int x=0,f=1;
    char ch=getchar();
    while(ch<'0'||ch>'9'){if(ch=='-')f=-1;ch=getchar();}
    while(ch>='0'&&ch<='9')x=x*10+ch-'0',ch=getchar();
    return x*f;
}
void write(ll x){
    if(x<0)putchar('-'),x=-x;
    if(x>9)write(x/10);
    putchar(x%10+'0');return;
}
ll a[65]={0ll};
ll f(int x)
{
	if(a[x])return a[x];
	if(x<1)return a[x]=0ll;
	if(x>0&&x<=2)return a[x]=1ll;
	return a[x]=f(x-1)+f(x-2)+f(x-3);
}
int n;
int main(void)
{
    a[-1]=a[-2]=a[-3]=0;
	write(f(read()+1));
	return false;
}
